import axios from 'axios';

// Create a new forum post
const createForumPost = async (postData, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.post('/api/forum', postData, config);
  return response.data;
};

// Get all forum posts
const getForumPosts = async () => {
  const response = await axios.get('/api/forum');
  return response.data;
};

// Get forum post by ID
const getForumPostById = async (postId) => {
  const response = await axios.get(`/api/forum/${postId}`);
  return response.data;
};

// Add comment to a forum post
const addComment = async (postId, commentData, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.post(`/api/forum/${postId}/comments`, commentData, config);
  return response.data;
};

// Delete a forum post
const deleteForumPost = async (postId, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.delete(`/api/forum/${postId}`, config);
  return response.data;
};

// Delete a comment
const deleteComment = async (postId, commentId, token) => {
  const config = {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  };

  const response = await axios.delete(`/api/forum/${postId}/comments/${commentId}`, config);
  return response.data;
};

const forumService = {
  createForumPost,
  getForumPosts,
  getForumPostById,
  addComment,
  deleteForumPost,
  deleteComment,
};

export default forumService;
